30	function assertPermutation(posted: string[], existing: (string | undefined)[], field: string): void {
31	  const have = existing.filter((id): id is string => Boolean(id));
32	  const postedSet = new Set(posted);
33	  if (posted.length !== have.length || postedSet.size !== posted.length || !have.every((id) => postedSet.has(id))) {
34	    throw AppError.badRequest(`${field} must list exactly the existing ids once each`);
35	  }
36	}
