57	  /** POST /subjects/import — импорт предмета целиком с книгами, главами, темами, параграфами */
58	  async importSubject(req: Request, res: Response): Promise<void> {
59	    const { title, description, books } = req.body;
60	    if (!title) throw AppError.badRequest('title is required');
61	
62	    const updateIfExists = req.body?.updateIfExists === true;
63	    const existing = await Subject.findOne({ title: title.trim() });
64	    if (existing && !updateIfExists) {
65	      throw AppError.badRequest(
66	        `Subject "${title}" already exists. Pass "updateIfExists": true in JSON to refresh description, subjectKind and books.`
67	      );
68	    }
69	    if (existing && updateIfExists) {
70	      const subjectKind = req.body?.subjectKind === 'profile' ? 'profile' : 'main';
71	      const booksArr = Array.isArray(books) ? books : [];
72	      await Subject.updateOne(
73	        { _id: existing._id },
74	        {
75	          $set: {
76	            description: description != null ? String(description).trim() : existing.description,
77	            subjectKind,
78	            books: booksArr
79	          }
80	        }
81	      );
82	      const subject = await Subject.findById(existing._id);
83	      if (!subject) throw AppError.notFound('Subject not found');
84	      const bookCount = subject.books?.length ?? 0;
85	      const chapterCount = subject.books.reduce((s: number, b: any) => s + (b.chapters?.length ?? 0), 0);
86	      const topicCount = subject.books.reduce(
87	        (s: number, b: any) => s + b.chapters.reduce((cs: number, c: any) => cs + (c.topics?.length ?? 0), 0),
88	        0
89	      );
90	      const paragraphCount = subject.books.reduce(
91	        (s: number, b: any) =>
92	          s +
93	          b.chapters.reduce(
94	            (cs: number, c: any) => cs + c.topics.reduce((ts: number, t: any) => ts + (t.paragraphs?.length ?? 0), 0),
95	            0
96	          ),
97	        0
98	      );
99	      success(
100	        res,
101	        {
102	          subject,
103	          stats: { books: bookCount, chapters: chapterCount, topics: topicCount, paragraphs: paragraphCount }
104	        },
105	        'Subject updated from import',
106	        200
107	      );
108	      return;
109	    }
110	
111	    const subjectKind =
112	      req.body?.subjectKind === 'profile' ? 'profile' : 'main';
113	
114	    const subject = await Subject.create({
115	      title: title.trim(),
116	      description: description || '',
117	      subjectKind,
118	      books: books || []
119	    });
120	
121	    const bookCount = subject.books?.length ?? 0;
122	    const chapterCount = subject.books.reduce((s: number, b: any) => s + (b.chapters?.length ?? 0), 0);
123	    const topicCount = subject.books.reduce(
124	      (s: number, b: any) => s + b.chapters.reduce((cs: number, c: any) => cs + (c.topics?.length ?? 0), 0), 0
125	    );
126	    const paragraphCount = subject.books.reduce(
127	      (s: number, b: any) => s + b.chapters.reduce(
128	        (cs: number, c: any) => cs + c.topics.reduce(
129	          (ts: number, t: any) => ts + (t.paragraphs?.length ?? 0), 0
130	        ), 0
131	      ), 0
132	    );
133	
134	    success(res, {
135	      subject,
136	      stats: { books: bookCount, chapters: chapterCount, topics: topicCount, paragraphs: paragraphCount }
137	    }, `Imported: ${bookCount} books, ${chapterCount} chapters, ${topicCount} topics, ${paragraphCount} paragraphs`, 201);
138	  }
