244	  async updateSubject(req: Request, res: Response): Promise<void> {
245	    const id = String(req.params.id);
246	    if (!mongoose.isValidObjectId(id)) throw AppError.badRequest('Invalid subject id');
247	
248	    const { title, description, subjectKind } = req.body;
249	    const $set: Record<string, string> = {};
250	    if (title !== undefined) {
251	      const t = String(title).trim();
252	      if (!t) throw AppError.badRequest('title cannot be empty');
253	      $set.title = t;
254	    }
255	    if (description !== undefined) {
256	      $set.description = String(description).trim();
257	    }
258	    if (subjectKind !== undefined) {
259	      const sk = String(subjectKind).trim();
260	      if (sk !== 'main' && sk !== 'profile') {
261	        throw AppError.badRequest('subjectKind must be main or profile');
262	      }
263	      $set.subjectKind = sk;
264	    }
265	
266	    if (Object.keys($set).length === 0) {
267	      const subject = await this.findSubject(id);
268	      success(res, subject, 'Subject updated');
269	      return;
270	    }
271	
272	    const subject = await Subject.findByIdAndUpdate(id, { $set }, { new: true, runValidators: true });
273	    if (!subject) throw AppError.notFound('Subject not found');
274	    success(res, subject, 'Subject updated');
275	  }
