280	  async deleteSubject(req: Request, res: Response): Promise<void> {
281	    const id = String(req.params.id);
282	    if (!mongoose.isValidObjectId(id)) throw AppError.badRequest('Invalid subject id');
283	    const oid = new mongoose.Types.ObjectId(id);
284	
285	    const exists = await Subject.findById(id).select('_id').lean();
286	    if (!exists) throw AppError.notFound('Subject not found');
287	
288	    const tests = await Test.find({ subjectId: oid }).select('_id').lean();
289	    const testIds = tests.map((t) => t._id);
290	    if (testIds.length) {
291	      await SoloSession.deleteMany({ testId: { $in: testIds } });
292	    }
293	    await SoloAttempt.deleteMany({ subjectId: oid });
294	    await Test.deleteMany({ subjectId: oid });
295	    await CanonicalRoadmap.deleteMany({ subjectId: oid });
296	    await KtpCatalog.deleteMany({ subjectId: oid });
297	    await NodeLessonContent.deleteMany({ subjectId: oid });
298	    await UserRoadmapProgress.deleteMany({ subjectId: oid });
299	    await RoadmapAttempt.deleteMany({ subjectId: oid });
300	    await RoadmapChatAttachment.deleteMany({ subjectId: oid });
301	
302	    const affectedPairs = await ProfileSubjectPair.find({
303	      $or: [{ subject1Id: oid }, { subject2Id: oid }]
304	    })
305	      .select('_id')
306	      .lean();
307	    const pairIds = affectedPairs.map((p) => p._id);
308	    if (pairIds.length) {
309	      await User.updateMany({ profileSubjectPairId: { $in: pairIds } }, { $unset: { profileSubjectPairId: 1 } });
310	    }
311	    await ProfileSubjectPair.deleteMany({ $or: [{ subject1Id: oid }, { subject2Id: oid }] });
312	
313	    await User.updateMany({ 'testHistory.subjectId': oid }, { $pull: { testHistory: { subjectId: oid } } });
314	
315	    await Subject.deleteOne({ _id: oid });
316	    success(res, { deleted: true }, 'Subject deleted');
317	  }
